example.code:
services: postgres: image: postgres:16-alpine environment: POSTGRES_DB: grafana POSTGRES_USER: grafana POSTGRES_PASSWORD: ${DB_PASSWORD} healthcheck: test: ["CMD-SHELL", "pg_isready -U grafana"] interval: 10s
grafana-1: image: grafana/grafana:11.6.0 environment: - GF_DATABASE_TYPE=postgres - GF_DATABASE_HOST=postgres:5432 - GF_DATABASE_NAME=grafana - GF_DATABASE_USER=grafana - GF_DATABASE_PASSWORD=${DB_PASSWORD} - GF_UNIFIED_ALERTING_HA_LISTEN_ADDRESS=0.0.0.0:9094 - GF_UNIFIED_ALERTING_HA_PEERS=grafana-2:9094 depends_on: postgres: {condition: service_healthy}
grafana-2: image: grafana/grafana:11.6.0 environment: - GF_DATABASE_TYPE=postgres - GF_DATABASE_HOST=postgres:5432 - GF_DATABASE_NAME=grafana - GF_DATABASE_USER=grafana - GF_DATABASE_PASSWORD=${DB_PASSWORD} - GF_UNIFIED_ALERTING_HA_LISTEN_ADDRESS=0.0.0.0:9094 - GF_UNIFIED_ALERTING_HA_PEERS=grafana-1:9094 depends_on: postgres: {condition: service_healthy}
nginx: image: nginx:alpine ports: ["443:443"] volumes: - ./nginx.conf:/etc/nginx/nginx.conf - ./certs:/etc/nginx/certs
